import React, { useState, useEffect } from "react";
import { fetchMenu } from "../services/api";

function FoodMenu() {
  const [menuItems, setMenuItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("all");

  useEffect(() => {
    fetchMenuItems();
  }, []);

  const fetchMenuItems = async () => {
    try {
      setLoading(true);
      const response = await fetchMenu();
      setMenuItems(response || []);
      setError(null);
    } catch (err) {
      console.error("Error fetching menu items:", err);
      setError("Failed to fetch menu items");
    } finally {
      setLoading(false);
    }
  };

  const getUniqueCategories = () => {
    const categories = [...new Set(menuItems.map((item) => item.category))];
    return categories.filter(Boolean).sort();
  };

  const filteredItems = menuItems.filter((item) => {
    const matchesSearch =
      item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.alpha_code?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.numeric_code?.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesCategory =
      selectedCategory === "all" || item.category === selectedCategory;

    return matchesSearch && matchesCategory;
  });

  if (loading) {
    return (
      <div className="food-menu">
        <h2>Food Menu</h2>
        <div className="loading">Loading menu items...</div>
      </div>
    );
  }

  return (
    <div className="food-menu">
      <div className="menu-header">
        <h2>Food Menu</h2>
        <button onClick={fetchMenuItems} className="refresh-btn">
          Refresh Menu
        </button>
      </div>

      {error && (
        <div className="error-message">
          {error}
          <button onClick={() => setError(null)}>×</button>
        </div>
      )}

      <div className="menu-controls">
        <div className="search-controls">
          <input
            type="text"
            placeholder="Search by name or code..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="search-input"
          />
        </div>

        <div className="filter-controls">
          <label>Category:</label>
          <select
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
            className="category-filter"
          >
            <option value="all">All Categories</option>
            {getUniqueCategories().map((category) => (
              <option key={category} value={category}>
                {category}
              </option>
            ))}
          </select>
        </div>
      </div>

      <div className="menu-stats">
        <span>Total Items: {menuItems.length}</span>
        <span>Filtered: {filteredItems.length}</span>
        <span>Categories: {getUniqueCategories().length}</span>
      </div>

      {filteredItems.length > 0 ? (
        <div className="menu-items-grid">
          {filteredItems.map((item) => (
            <div key={item.id} className="menu-item-card">
              <div className="item-header">
                <h3 className="item-name">{item.name}</h3>
                <span className="item-category">
                  {item.category || "Uncategorized"}
                </span>
              </div>

              <div className="item-codes">
                {item.alpha_code && (
                  <span className="code alpha-code">
                    Code: {item.alpha_code}
                  </span>
                )}
                {item.numeric_code && (
                  <span className="code numeric-code">
                    Numeric: {item.numeric_code}
                  </span>
                )}
              </div>

              <div className="item-prices">
                <div className="price-row">
                  <span className="price-label">General:</span>
                  <span className="price-value">
                    ₹{item.price_general?.toFixed(2) || "0.00"}
                  </span>
                </div>

                <div className="price-row">
                  <span className="price-label">AC:</span>
                  <span className="price-value">
                    ₹{item.price_ac?.toFixed(2) || "0.00"}
                  </span>
                </div>

                <div className="price-row">
                  <span className="price-label">Fixed:</span>
                  <span className="price-value">
                    ₹{item.price_fixed?.toFixed(2) || "0.00"}
                  </span>
                </div>
              </div>

              <div className="item-status">
                <span
                  className={`status ${item.is_active ? "active" : "inactive"}`}
                >
                  {item.is_active ? "Available" : "Unavailable"}
                </span>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="no-items">
          {searchTerm || selectedCategory !== "all"
            ? "No items match your search criteria"
            : "No menu items available"}
        </div>
      )}
    </div>
  );
}

export default FoodMenu;
